// src/components/TrialsManager.js - Horizontal Layout with Detail View
import React, { useState, useEffect } from 'react';
import { FlaskConical, Plus, Edit2, Trash2, Upload, X, Save, ArrowLeft, FileText } from 'lucide-react';

const TrialsManager = ({ token }) => {
  const [trials, setTrials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingTrial, setEditingTrial] = useState(null);
  const [selectedTrial, setSelectedTrial] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    condition: '',
    phase: '',
    inclusion_criteria: '',
    exclusion_criteria: ''
  });

  const API_BASE = 'http://localhost:8000/api';

  useEffect(() => {
    loadTrials();
  }, [token]);

  const loadTrials = async () => {
    try {
      const response = await fetch(`${API_BASE}/trials`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await response.json();
      
      // Ensure data is always an array
      setTrials(Array.isArray(data) ? data : []);
      console.log('Trials loaded:', data);
    } catch (error) {
      console.error('Failed to load trials:', error);
      setTrials([]);
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    try {
      // ✅ Convert newline-separated string to array
      const inclusionArray = formData.inclusion_criteria
        .split('\n')
        .map(item => item.trim())
        .filter(item => item.length > 0);
      
      const exclusionArray = formData.exclusion_criteria
        .split('\n')
        .map(item => item.trim())
        .filter(item => item.length > 0);
  
      const response = await fetch(`${API_BASE}/trials`, {
        method: 'POST',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          title: formData.title,
          condition: formData.condition,
          phase: formData.phase,
          inclusion_criteria: inclusionArray,  // ✅ Send as array
          exclusion_criteria: exclusionArray   // ✅ Send as array
        })
      });
  
      if (response.ok) {
        await loadTrials();
        closeModal();
        alert('Trial created successfully!');
      } else {
        const error = await response.json();
        alert(`Failed to create trial: ${error.detail || 'Unknown error'}`);
      }
    } catch (error) {
      console.error('Failed to create trial:', error);
      alert('Failed to create trial. Check console for details.');
    }
  };
  
  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      // ✅ Convert newline-separated string to array
      const inclusionArray = formData.inclusion_criteria
        .split('\n')
        .map(item => item.trim())
        .filter(item => item.length > 0);
      
      const exclusionArray = formData.exclusion_criteria
        .split('\n')
        .map(item => item.trim())
        .filter(item => item.length > 0);
  
      const response = await fetch(`${API_BASE}/trials/${editingTrial.id}`, {
        method: 'PUT',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          title: formData.title,
          condition: formData.condition,
          phase: formData.phase,
          inclusion_criteria: inclusionArray,  // ✅ Send as array
          exclusion_criteria: exclusionArray   // ✅ Send as array
        })
      });
  
      if (response.ok) {
        const updatedTrial = await response.json();
        await loadTrials();
        closeModal();
        setSelectedTrial(updatedTrial);
        alert('Trial updated successfully!');
      } else {
        const error = await response.json();
        alert(`Failed to update trial: ${error.detail || 'Unknown error'}`);
      }
    } catch (error) {
      console.error('Failed to update trial:', error);
      alert('Failed to update trial. Check console for details.');
    }
  };
  
  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this trial?')) return;

    try {
      const response = await fetch(`${API_BASE}/trials/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });

      if (response.ok) {
        await loadTrials();
        setSelectedTrial(null);
      }
    } catch (error) {
      console.error('Failed to delete trial:', error);
    }
  };

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('file', file);

    try {
      const response = await fetch(`${API_BASE}/trials/upload`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
        body: formData
      });

      if (response.ok) {
        await loadTrials();
        alert('Trial uploaded successfully!');
      }
    } catch (error) {
      console.error('Failed to upload trial:', error);
    }
  };

  const openEditModal = (trial) => {
    setEditingTrial(trial);
    setFormData({
      title: trial.title || '',
      condition: trial.condition || '',
      phase: trial.phase || '',
      inclusion_criteria: trial.inclusion_criteria?.join('\n') || '',
      exclusion_criteria: trial.exclusion_criteria?.join('\n') || ''
    });
    setSelectedTrial(null); // Close detail view first
    setShowModal(true);
  };

  const openCreateModal = () => {
    setEditingTrial(null);
    setFormData({
      title: '',
      condition: '',
      phase: '',
      inclusion_criteria: '',
      exclusion_criteria: ''
    });
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingTrial(null);
  };

  const styles = {
    container: { color: 'white', padding: '40px' },
    header: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      marginBottom: '32px'
    },
    title: { 
      fontSize: '48px', 
      fontWeight: '800',
      background: 'linear-gradient(135deg, #8b5cf6 0%, #7c3aed 100%)',
      WebkitBackgroundClip: 'text',
      WebkitTextFillColor: 'transparent'
    },
    buttonGroup: { display: 'flex', gap: '12px' },
    button: {
      padding: '14px 24px',
      background: 'linear-gradient(135deg, #8b5cf6 0%, #7c3aed 100%)',
      border: 'none',
      borderRadius: '12px',
      color: 'white',
      fontSize: '14px',
      fontWeight: '600',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      transition: 'all 0.3s ease'
    },
    horizontalScroll: {
      display: 'flex',
      gap: '16px',
      overflowX: 'auto',
      paddingBottom: '16px',
      marginBottom: '32px',
      scrollBehavior: 'smooth'
    },
    trialCard: {
      minWidth: '280px',
      background: 'rgba(139, 92, 246, 0.1)',
      border: '2px solid rgba(139, 92, 246, 0.3)',
      padding: '20px',
      borderRadius: '16px',
      cursor: 'pointer',
      transition: 'all 0.3s ease',
      flex: '0 0 auto'
    },
    detailCard: {
      background: 'rgba(30, 41, 59, 0.6)',
      backdropFilter: 'blur(10px)',
      padding: '32px',
      borderRadius: '24px',
      border: '1px solid rgba(100,116,139,0.3)',
    },
    modal: {
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: 'rgba(0,0,0,0.7)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 1000
    },
    modalContent: {
      background: 'rgba(30, 41, 59, 0.95)',
      padding: '32px',
      borderRadius: '24px',
      width: '600px',
      maxHeight: '80vh',
      overflowY: 'auto'
    },
    input: {
      width: '100%',
      padding: '12px',
      background: 'rgba(15, 23, 42, 0.5)',
      border: '1px solid rgba(100,116,139,0.3)',
      borderRadius: '8px',
      color: 'white',
      fontSize: '14px',
      marginBottom: '16px'
    },
    textarea: {
      width: '100%',
      minHeight: '120px',
      padding: '12px',
      background: 'rgba(15, 23, 42, 0.5)',
      border: '1px solid rgba(100,116,139,0.3)',
      borderRadius: '8px',
      color: 'white',
      fontSize: '14px',
      marginBottom: '16px',
      fontFamily: 'inherit',
      resize: 'vertical'
    },
    label: {
      display: 'block',
      color: '#cbd5e1',
      fontSize: '14px',
      fontWeight: '600',
      marginBottom: '8px'
    },
    criteriaBox: {
      background: 'rgba(15, 23, 42, 0.5)',
      padding: '20px',
      borderRadius: '12px',
      marginBottom: '16px'
    },
    criteriaItem: {
      padding: '12px',
      background: 'rgba(139, 92, 246, 0.1)',
      borderLeft: '3px solid #8b5cf6',
      borderRadius: '8px',
      marginBottom: '8px',
      fontSize: '14px',
      lineHeight: '1.6'
    }
  };

  if (loading) return <div style={styles.container}>Loading trials...</div>;

  // Detail View
  if (selectedTrial) {
    return (
      <div style={styles.container}>
        <button
          style={{ ...styles.button, marginBottom: '24px' }}
          onClick={() => setSelectedTrial(null)}
        >
          <ArrowLeft size={18} />
          Back to List
        </button>

        <div style={styles.detailCard}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '32px' }}>
            <div>
              <h1 style={{ fontSize: '36px', fontWeight: '800', marginBottom: '8px' }}>
                {selectedTrial.title}
              </h1>
              <div style={{ color: '#94a3b8', fontSize: '16px' }}>
                Trial ID: {selectedTrial.trial_id}
              </div>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button
                onClick={() => openEditModal(selectedTrial)}
                style={{
                  ...styles.button,
                  background: 'rgba(139, 92, 246, 0.2)',
                  border: '1px solid rgba(139, 92, 246, 0.3)'
                }}
              >
                <Edit2 size={18} />
                Edit
              </button>
              <button
                onClick={() => handleDelete(selectedTrial.id)}
                style={{
                  ...styles.button,
                  background: 'rgba(239, 68, 68, 0.2)',
                  border: '1px solid rgba(239, 68, 68, 0.3)'
                }}
              >
                <Trash2 size={18} />
                Delete
              </button>
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '24px', marginBottom: '32px' }}>
            <div>
              <div style={{ fontSize: '12px', color: '#94a3b8', textTransform: 'uppercase', marginBottom: '8px' }}>
                Condition
              </div>
              <div style={{ fontSize: '18px', color: 'white', fontWeight: '600' }}>
                {selectedTrial.condition || 'N/A'}
              </div>
            </div>
            <div>
              <div style={{ fontSize: '12px', color: '#94a3b8', textTransform: 'uppercase', marginBottom: '8px' }}>
                Phase
              </div>
              <div style={{ fontSize: '18px', color: 'white', fontWeight: '600' }}>
                {selectedTrial.phase || 'N/A'}
              </div>
            </div>
          </div>

          <div style={{ marginBottom: '32px' }}>
            <h3 style={{ fontSize: '20px', fontWeight: '700', marginBottom: '16px', color: '#10b981' }}>
              ✓ Inclusion Criteria
            </h3>
            <div style={styles.criteriaBox}>
              {selectedTrial.inclusion_criteria && selectedTrial.inclusion_criteria.length > 0 ? (
                selectedTrial.inclusion_criteria.map((criterion, idx) => (
                  <div key={idx} style={styles.criteriaItem}>
                    {idx + 1}. {criterion}
                  </div>
                ))
              ) : (
                <div style={{ color: '#94a3b8' }}>No inclusion criteria specified</div>
              )}
            </div>
          </div>

          <div>
            <h3 style={{ fontSize: '20px', fontWeight: '700', marginBottom: '16px', color: '#ef4444' }}>
              ✗ Exclusion Criteria
            </h3>
            <div style={styles.criteriaBox}>
              {selectedTrial.exclusion_criteria && selectedTrial.exclusion_criteria.length > 0 ? (
                selectedTrial.exclusion_criteria.map((criterion, idx) => (
                  <div key={idx} style={{...styles.criteriaItem, borderColor: '#ef4444', background: 'rgba(239, 68, 68, 0.1)'}}>
                    {idx + 1}. {criterion}
                  </div>
                ))
              ) : (
                <div style={{ color: '#94a3b8' }}>No exclusion criteria specified</div>
              )}
            </div>
          </div>

          <div style={{
  background: 'rgba(139, 92, 246, 0.1)',
  border: '1px solid rgba(139, 92, 246, 0.3)',
  borderRadius: '12px',
  padding: '16px',
  marginTop: '24px'
}}>
  <div style={{ fontSize: '14px', color: '#8b5cf6', fontWeight: '600', marginBottom: '12px' }}>
    🤖 ML-Extracted Trial Protocol
  </div>
  
  {/* ✅ Show extraction details */}
  <div style={{ fontSize: '14px', color: '#cbd5e1', lineHeight: '1.8' }}>
    {selectedTrial.pdf_url && (
      <div style={{ marginBottom: '12px', padding: '12px', background: 'rgba(139, 92, 246, 0.1)', borderRadius: '8px' }}>
        <strong style={{ color: '#8b5cf6' }}>📄 Source:</strong> Extracted from protocol PDF document
      </div>
    )}
    
    {selectedTrial.extracted_at && (
      <div style={{ marginBottom: '12px' }}>
        <strong>⏱️ Processed:</strong> {new Date(selectedTrial.extracted_at).toLocaleString()}
      </div>
    )}
    
    {/* Show what was extracted */}
    <div style={{ marginTop: '16px', padding: '16px', background: 'rgba(15, 23, 42, 0.5)', borderRadius: '8px' }}>
      <div style={{ fontSize: '13px', color: '#94a3b8', marginBottom: '12px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '1px' }}>
        🔬 Auto-Extracted Protocol Elements
      </div>
      
      <div style={{ display: 'grid', gap: '8px' }}>
        {selectedTrial.title && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span>Trial title identified: <strong>{selectedTrial.title.substring(0, 40)}...</strong></span>
          </div>
        )}
        
        {selectedTrial.condition && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span>Primary condition: <strong>{selectedTrial.condition}</strong></span>
          </div>
        )}
        
        {selectedTrial.inclusion_criteria && selectedTrial.inclusion_criteria.length > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span><strong>{selectedTrial.inclusion_criteria.length}</strong> inclusion criteria parsed using NLP</span>
          </div>
        )}
        
        {selectedTrial.exclusion_criteria && selectedTrial.exclusion_criteria.length > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span><strong>{selectedTrial.exclusion_criteria.length}</strong> exclusion criteria parsed using NLP</span>
          </div>
        )}
        
        {selectedTrial.phase && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span>Trial phase: <strong>{selectedTrial.phase}</strong></span>
          </div>
        )}
        
        {(!selectedTrial.inclusion_criteria || selectedTrial.inclusion_criteria.length === 0) &&
         (!selectedTrial.exclusion_criteria || selectedTrial.exclusion_criteria.length === 0) && (
          <div style={{ color: '#94a3b8', fontStyle: 'italic' }}>
            Manually entered trial data (no PDF extraction)
          </div>
        )}
      </div>
    </div>
    
    <div style={{ marginTop: '12px', fontSize: '13px', fontStyle: 'italic', color: '#94a3b8' }}>
      This trial protocol was {selectedTrial.pdf_url ? 'automatically extracted and ' : ''}structured using NLP models. 
      Criteria have been parsed for semantic similarity matching with patient profiles.
    </div>
  </div>
</div>

        </div>
      </div>
    );
  }

  // Horizontal List View
  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>Clinical Trials</h1>
        <div style={styles.buttonGroup}>
          <label htmlFor="upload-trial" style={styles.button}>
            <Upload size={18} />
            Upload PDF
          </label>
          <input
            id="upload-trial"
            type="file"
            accept=".pdf"
            onChange={handleUpload}
            style={{ display: 'none' }}
          />
          <button style={styles.button} onClick={openCreateModal}>
            <Plus size={18} />
            Add Trial
          </button>
        </div>
      </div>

      {trials.length === 0 ? (
        <div style={styles.detailCard}>
          <div style={{ textAlign: 'center', padding: '40px' }}>
            <FlaskConical size={64} style={{ opacity: 0.3, margin: '0 auto 16px' }} />
            <div style={{ fontSize: '20px', marginBottom: '8px' }}>No trials yet</div>
            <div style={{ color: '#94a3b8' }}>Upload a PDF or add your first trial manually!</div>
          </div>
        </div>
      ) : (
        <>
          <div style={{ fontSize: '14px', color: '#94a3b8', marginBottom: '16px' }}>
            Scroll horizontally to view all trials ➔
          </div>
          <div style={styles.horizontalScroll}>
            {trials.map((trial) => (
              <div
                key={trial.id}
                style={styles.trialCard}
                onClick={() => setSelectedTrial(trial)}
                onMouseEnter={(e) => {
                  e.currentTarget.style.transform = 'translateY(-4px)';
                  e.currentTarget.style.boxShadow = '0 12px 32px rgba(139, 92, 246, 0.3)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                <div style={{ marginBottom: '16px' }}>
                  <FlaskConical size={32} color="#8b5cf6" />
                </div>
                <h3 style={{ fontSize: '18px', fontWeight: '700', marginBottom: '8px' }}>
                  {trial.title}
                </h3>
                <div style={{ color: '#a78bfa', fontSize: '14px', marginBottom: '12px' }}>
                  {trial.condition || 'Unknown'} • {trial.phase || 'N/A'}
                </div>
                <div style={{ fontSize: '12px', color: '#cbd5e1' }}>
                  Click to view full details →
                </div>
              </div>
            ))}
          </div>
        </>
      )}

      {/* Modal for Add/Edit */}
      {showModal && (
        <div style={styles.modal} onClick={closeModal}>
          <div style={styles.modalContent} onClick={(e) => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '24px' }}>
              <h2 style={{ fontSize: '24px' }}>
                {editingTrial ? 'Edit Trial' : 'Add New Trial'}
              </h2>
              <button onClick={closeModal} style={{ background: 'none', border: 'none', color: 'white', cursor: 'pointer' }}>
                <X size={24} />
              </button>
            </div>

            <form onSubmit={editingTrial ? handleUpdate : handleCreate}>
              <label style={styles.label}>Trial Title</label>
              <input
                type="text"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                style={styles.input}
                required
              />

              <label style={styles.label}>Condition</label>
              <input
                type="text"
                value={formData.condition}
                onChange={(e) => setFormData({ ...formData, condition: e.target.value })}
                style={styles.input}
                required
              />

              <label style={styles.label}>Phase</label>
              <select
                value={formData.phase}
                onChange={(e) => setFormData({ ...formData, phase: e.target.value })}
                style={styles.input}
              >
                <option value="">Select Phase</option>
                <option value="Phase 1">Phase 1</option>
                <option value="Phase 2">Phase 2</option>
                <option value="Phase 3">Phase 3</option>
                <option value="Phase 4">Phase 4</option>
              </select>

              <label style={styles.label}>Inclusion Criteria (one per line)</label>
              <textarea
                value={formData.inclusion_criteria}
                onChange={(e) => setFormData({ ...formData, inclusion_criteria: e.target.value })}
                style={styles.textarea}
                placeholder="Age 18-75 years&#10;Diagnosed with Type 2 Diabetes&#10;HbA1c between 7.0% and 10.5%"
              />

              <label style={styles.label}>Exclusion Criteria (one per line)</label>
              <textarea
                value={formData.exclusion_criteria}
                onChange={(e) => setFormData({ ...formData, exclusion_criteria: e.target.value })}
                style={styles.textarea}
                placeholder="Pregnant or breastfeeding&#10;Severe kidney disease&#10;Recent hospitalization"
              />

              <button type="submit" style={{ ...styles.button, width: '100%', justifyContent: 'center' }}>
                <Save size={18} />
                {editingTrial ? 'Update Trial' : 'Create Trial'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TrialsManager;
